define i8 @smax_of_sub_nsw_r(i8 %a, i8 %b, i8 %c) {
  %sub1 = sub nsw i8 %a, %c
  %sub2 = sub nsw i8 %b, %c
  %res = call i8 @llvm.smax.i8(i8 %sub1, i8 %sub2)
  ret i8 %res
}

define i8 @smin_of_add(i8 %a, i8 %b, i8 %c) {
  %add1 = add i8 %b, %a
  %add2 = add i8 %c, %a
  %min = call i8 @llvm.smin.i8(i8 %add1, i8 %add2)
  ret i8 %min
}

